    FLAGS = 5,
    DISPLAY_NAME = 6,
    JOINT = 7,
    ORIENTATION = 8,
	TYPE = 9,
	COMBINE = 10,
	RING = 11
}

local function GetInventoryData(row)
    return {
        itemID = row[COL.ITEM_ID],
        yOffset = row[COL.YOFFSET],
        scale = row[COL.SCALE],
        rotation = row[COL.ROTATION],
        flags = row[COL.FLAGS],
        name = row[COL.DISPLAY_NAME],
        joint = row[COL.JOINT],
        orientation = row[COL.ORIENTATION],
		type = row[COL.TYPE],
		combine = row[COL.COMBINE],
		ring = row[COL.RING],
    }
end

